body {
  -webkit-font-smoothing: antialiased; /* For macOS & iOS */
  -moz-osx-font-smoothing: grayscale; /* For macOS & iOS */
  text-rendering: optimizeLegibility; /* Standard for advanced font rendering */
}

/* Consider performance for very large text areas */
.performance-critical-area {
  text-rendering: optimizeSpeed; /* Prioritize speed for large blocks of less critical text */
}
